import { createHmac } from 'node:crypto';

import {
  AdminCreateUserCommand,
  AdminCreateUserCommandInput,
  AdminDeleteUserCommand,
  AdminGetUserCommand,
  AdminSetUserPasswordCommand,
  AttributeType,
  CognitoIdentityProviderClient,
  ConfirmForgotPasswordCommand,
  ForgotPasswordCommand,
  GetUserCommand,
  GlobalSignOutCommand,
  InitiateAuthCommand,
  ResendConfirmationCodeCommand,
  RespondToAuthChallengeCommand,
} from '@aws-sdk/client-cognito-identity-provider';
import { Injectable, Logger, UnauthorizedException } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { CognitoJwtVerifier } from 'aws-jwt-verify';
import axios from 'axios';
import { env } from '@/env';

const cognitoHeaders = {
  'Content-Type': 'application/x-www-form-urlencoded',
};

function createTempPassword() {
  return '!tP' + Date.now();
}

@Injectable()
export class CognitoService {
  private readonly logger = new Logger(CognitoService.name);
  private readonly cognitoClient: CognitoIdentityProviderClient;
  private readonly userPoolId: string;
  private readonly clientId: string;
  private readonly clientSecret: string;
  private readonly cognitoUrl: string;

  constructor(private readonly configService: ConfigService) {
    this.cognitoClient = new CognitoIdentityProviderClient({
      endpoint: this.configService.get('AWS_COGNITO_ENDPOINT'),
      region: this.configService.get('AWS_COGNITO_REGION'),
      credentials: {
        accessKeyId: this.configService.get('AWS_ACCESS_KEY_ID')!,
        secretAccessKey: this.configService.get('AWS_SECRET_ACCESS_KEY')!,
      },
    });
    this.userPoolId = this.configService.get('AWS_COGNITO_USER_POOL_ID')!;
    this.clientId = this.configService.get('AWS_COGNITO_CLIENT_ID')!;
    this.clientSecret = this.configService.get('AWS_COGNITO_CLIENT_SECRET')!;
    this.cognitoUrl = this.configService.get('AWS_COGNITO_URL')!;
  }

  async respondToNewPasswordChallenge(
    email: string,
    newPassword: string,
    session: string,
  ) {
    const params = {
      ClientId: this.clientId,
      ChallengeName: 'NEW_PASSWORD_REQUIRED' as const,
      Session: session,
      ChallengeResponses: {
        USERNAME: email,
        NEW_PASSWORD: newPassword,
        SECRET_HASH: this.generateSecretHash(email),
      },
    };

    const command = new RespondToAuthChallengeCommand(params);
    return this.cognitoClient.send(command);
  }

  async deleteUser(email: string) {
    return this.cognitoClient.send(
      new AdminDeleteUserCommand({
        UserPoolId: this.userPoolId,
        Username: email,
      }),
    );
  }

  async signupWithoutConfirmation(dto: {
    email: string;
    phone: string;
    firstName: string;
    lastName: string;
    patronymic?: string | null;
  }) {
    const { email, phone, firstName, lastName, patronymic } = dto;
    const fullName = [firstName, patronymic, lastName].filter(Boolean).join(' ');

    const tempPassword = createTempPassword();

    const result = await this.cognitoClient.send(
      new AdminCreateUserCommand({
        UserPoolId: this.userPoolId,
        Username: email,
        MessageAction: 'SUPPRESS',
        UserAttributes: [
          { Name: 'email', Value: email },
          { Name: 'email_verified', Value: 'true' },
          { Name: 'phone_number', Value: phone },
          { Name: 'phone_number_verified', Value: 'true' },
          { Name: 'name', Value: fullName },
        ],
        TemporaryPassword: tempPassword,
      }),
    );

    return { result, tempPassword };
  }

  async signUp(dto: {
    email: string;
    firstName: string;
    lastName: string;
    patronymic?: string | null;
    password: string;
  }) {
    const { email, firstName, lastName, patronymic, password } = dto;
    const fullName = [firstName, patronymic, lastName].filter(Boolean).join(' ');

    const params: AdminCreateUserCommandInput = {
      UserPoolId: this.userPoolId,
      Username: email,
      UserAttributes: [
        { Name: 'email', Value: email },
        { Name: 'email_verified', Value: 'true' },
        { Name: 'name', Value: fullName },
      ],
      MessageAction: 'SUPPRESS',
    };

    this.logger.log(`[signUp] AdminCreateUser for: ${email}`);
    const command = new AdminCreateUserCommand(params);
    try {
      await this.cognitoClient.send(command);
      this.logger.log(`[signUp] AdminCreateUser success for: ${email}`);
    } catch (error) {
      this.logger.error(
        `[signUp] AdminCreateUser failed for ${email}: [${error?.name}] ${error?.message}`,
        error?.stack,
      );
      throw error;
    }

    // Set password permanently so user is CONFIRMED
    this.logger.log(`[signUp] AdminSetUserPassword for: ${email}`);
    try {
      await this.changePassword(email, password);
      this.logger.log(`[signUp] AdminSetUserPassword success for: ${email}`);
    } catch (error) {
      this.logger.error(
        `[signUp] AdminSetUserPassword failed for ${email}: [${error?.name}] ${error?.message}`,
        error?.stack,
      );
      throw error;
    }
  }

  async resendConfirmationCode(email: string) {
    return this.cognitoClient.send(
      new ResendConfirmationCodeCommand({
        ClientId: this.clientId,
        Username: email,
        SecretHash: this.generateSecretHash(email),
      }),
    );
  }

  async signIn(email: string, password: string) {
    if (env.AWS_COGNITO_SKIP) {
      return {
        AuthenticationResult: {
          AccessToken: Date.now().toString(),
          RefreshToken: Date.now().toString(),
          IdToken: Date.now().toString(),
        },
        ChallengeName: null,
      };
    }

    const params = {
      ClientId: this.clientId,
      AuthFlow: 'USER_PASSWORD_AUTH' as const,
      AuthParameters: {
        USERNAME: email,
        PASSWORD: password,
        SECRET_HASH: this.generateSecretHash(email),
      },
    };

    const command = new InitiateAuthCommand(params);
    return this.cognitoClient.send(command);
  }

  async refreshToken(refreshToken: string, accessToken: string) {
    if (env.AWS_COGNITO_SKIP) {
      return {
        AuthenticationResult: {
          AccessToken: Date.now().toString(),
          RefreshToken: Date.now().toString(),
          IdToken: Date.now().toString(),
        },
        ChallengeName: null,
      };
    }

    const tokenPayload = this.decodeJwtToken(accessToken);

    if (!tokenPayload?.username) {
      throw new UnauthorizedException('Invalid access token');
    }

    return this.cognitoClient.send(
      new InitiateAuthCommand({
        AuthFlow: 'REFRESH_TOKEN_AUTH',
        ClientId: this.clientId,
        AuthParameters: {
          SECRET_HASH: this.generateSecretHash(tokenPayload.username),
          REFRESH_TOKEN: refreshToken,
        },
      }),
    );
  }

  async signOut(accessToken: string) {
    return this.cognitoClient.send(
      new GlobalSignOutCommand({
        AccessToken: accessToken,
      }),
    );
  }

  async forgotPassword(email: string) {
    const params = {
      ClientId: this.clientId,
      Username: email,
      SecretHash: this.generateSecretHash(email),
    };

    const command = new ForgotPasswordCommand(params);
    return this.cognitoClient.send(command);
  }

  async changePassword(email: string, newPassword: string) {
    const params = {
      UserPoolId: this.userPoolId,
      ClientId: this.clientId,
      Username: email,
      Password: newPassword,
      SecretHash: this.generateSecretHash(email),
      Permanent: true,
    };

    const command = new AdminSetUserPasswordCommand(params);
    return this.cognitoClient.send(command);
  }

  async confirmForgotPassword(
    email: string,
    confirmationCode: string,
    newPassword: string,
  ) {
    const params = {
      ClientId: this.clientId,
      Username: email,
      ConfirmationCode: confirmationCode,
      Password: newPassword,
      SecretHash: this.generateSecretHash(email),
    };

    const command = new ConfirmForgotPasswordCommand(params);
    return this.cognitoClient.send(command);
  }

  async signInWithSocial(code: string, redirectUrl: string) {
    const body = new URLSearchParams({
      grant_type: 'authorization_code',
      client_id: this.clientId,
      redirect_uri: redirectUrl,
      code,
      client_secret: this.clientSecret,
    });

    const url = this.cognitoUrl;

    const { data } = await axios.post(`${url}/oauth2/token`, body, {
      headers: cognitoHeaders,
    });

    const areAllTokensReceived =
      data.access_token && data.refresh_token && data.id_token;

    if (!areAllTokensReceived) {
      throw new UnauthorizedException();
    }

    const userInfo = await this.getUserByAccessToken(data.access_token);

    return {
      ...userInfo,
      accessToken: data.access_token,
      refreshToken: data.refresh_token,
    };
  }

  async getUserByAccessToken(accessToken: string) {
    const result = await this.cognitoClient.send(
      new GetUserCommand({
        AccessToken: accessToken,
      }),
    );

    if (!result.UserAttributes) {
      throw new UnauthorizedException();
    }

    return this.getUserAttributesFromRaw(result.UserAttributes);
  }

  private generateSecretHash(username: string): string {
    return createHmac('SHA256', this.clientSecret)
      .update(username + this.clientId)
      .digest('base64');
  }

  private async getUserAttributesFromRaw(
    userAttributes: AttributeType[],
  ): Promise<{
    email: string;
    firstName: string;
    lastName: string;
    phone: string;
  }> {
    const res = userAttributes.reduce((acc, attribute) => {
      acc[attribute.Name!] = attribute.Value;
      return acc;
    }, {}) as {
      email: string;
      name: string;
      given_name?: string;
      family_name?: string;
      phone_number: string;
    };

    const nameParts = (res.name || '').trim().split(/\s+/);
    const firstName = res.given_name || nameParts[0] || '';
    const lastName = res.family_name || (nameParts.length > 1 ? nameParts[nameParts.length - 1] : '');

    return {
      email: res.email,
      firstName,
      lastName,
      phone: res.phone_number,
    };
  }

  private async getUserByEmail(email: string) {
    return this.cognitoClient.send(
      new AdminGetUserCommand({
        UserPoolId: this.userPoolId,
        Username: email,
      }),
    );
  }

  async getAccessTokenOwnerEmail(accessToken: string) {
    const verifier = CognitoJwtVerifier.create({
      userPoolId: this.userPoolId,
      tokenUse: 'access',
      clientId: this.clientId,
    });

    const payload = await verifier.verify(accessToken, {
      clientId: this.clientId,
      tokenUse: 'access',
      includeRawJwtInErrors: true,
    });

    const user = await this.cognitoClient.send(
      new AdminGetUserCommand({
        UserPoolId: this.userPoolId,
        Username: payload.username,
      }),
    );

    if (!user || !user.UserAttributes) {
      throw new UnauthorizedException('Email is not registered');
    }

    const attributes = user.UserAttributes.reduce((acc, attribute) => {
      if (attribute.Name) {
        acc[attribute.Name] = attribute.Value;
      }
      return acc;
    }, {}) as Record<string, string>;

    const email = attributes.email ? attributes.email : null;

    if (!email) {
      throw new UnauthorizedException(`User doesn't have email`);
    }

    return email;
  }

  async getUserAttributesByEmail(email: string) {
    const result = await this.getUserByEmail(email);

    if (!result.UserAttributes) {
      return null;
    }

    return this.getUserAttributesFromRaw(result.UserAttributes);
  }

  private decodeJwtToken(token: string): Record<string, string> | null {
    try {
      const base64Url = token.split('.')[1];
      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
      const jsonPayload = decodeURIComponent(
        Buffer.from(base64, 'base64')
          .toString()
          .split('')
          .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
          .join(''),
      );
      return JSON.parse(jsonPayload) as Record<string, string>;
    } catch {
      return null;
    }
  }
}

