  ENTRUPY_VALUE_THRESHOLD_CENTS: z.coerce.number().min(0).default(500000), // $5,000
  ENTRUPY_MISMATCH_THRESHOLD_CENTS: z.coerce.number().min(0).default(50000), // $500
