import { z } from 'zod';

const zBoolean = () =>
  z
    .union([z.literal('true'), z.literal('false'), z.undefined()])
    .transform((value) => {
      if (value === undefined) {
        return value;
      }

      if (value === 'true') {
        return true;
      }

      return false;
    });

const zStrArray = () =>
  z.union([
    z.undefined().transform(() => [] as string[]),
    z
      .string()
      .transform((origins) =>
        origins.split(',').map((origin) => origin.trim()),
      ),
  ]);

export const NODE_ENV_SCHEMA = z.object({
  NODE_ENV: z.union([
    z.undefined(),
    z.literal('development'),
    z.literal('production'),
    z.literal('test'),
  ]),
});

export const CORE_ENV_SCHEMA = z.object({
  CORE_PUBLIC_URL: z.string(),
  CORE_HOST: z.union([z.literal('localhost'), z.string()]),
  CORE_PORT: z.number({ coerce: true }).positive().int(),
  CORE_ORIGINS: zStrArray(),
  CORE_THROTTLE_ENABLED: zBoolean(),
  CORE_SUPER_ADMIN_EMAIL: z.string().email(),
});

export const JWT_ENV_SCHEMA = z.object({
  JWT_SECRET: z.string(),
});

export const SWAGGER_ENV_SCHEMA = z.object({
  SWAGGER_ENDPOINT: z.string(),
});

export const DB_ENV_SCHEMA = z.object({
  DB_HOST: z.string(),
  DB_PORT: z.number({ coerce: true }).positive().int(),
  DB_NAME: z.string(),
  DB_USER: z.string(),
  DB_PASSWORD: z.string(),
  DB_AUTO_SYNCHRONIZE: zBoolean(),
  DB_AUTO_MIGRATIONS_RUN: zBoolean(),
  DB_LOGGING: zBoolean(),
  DB_SSL: zBoolean(),
});

export const AWS_ENV_SCHEMA = z.object({
