});

export const MAIL_ENV_SCHEMA = z.object({
  MAIL_SENDER_EMAIL: z.string().email(),
  MAIL_REPLY_TO_EMAIL: z.string().email(),
  MAIL_ENABLED: zBoolean(),
});

export const MAILERSEND_ENV_SCHEMA = z.object({
  MAILERSEND_API_KEY: z.string(),
});

export const PHONE_NOTIFICATION_ENV_SCHEMA = z.object({
  PHONE_NOTIFICATION_ENABLED: zBoolean(),
});

export const AWS_COGNITO_ENV_SCHEMA = z.object({
