  ENTRUPY_API_URL: z.string().url().default('https://api.entrupy.com/v2'),
  ENTRUPY_API_TOKEN: z.string().optional(),
  ENTRUPY_WEBHOOK_SECRET: z.string().optional(),
  ENTRUPY_ENABLED: zBoolean().default('false'),
