  // Optional webhook signature secret (required if webhooks are used)
  CRYPTO_PAY_SIGNATURE_SECRET: z.string().optional(),
});

export const NOWPAYMENTS_ENV_SCHEMA = z.object({
  // API Key
  NOWPAYMENTS_API_KEY: z.string(),

  // Payout authorization (email/password for /auth)
  NOWPAYMENTS_AUTH_EMAIL: z.string(),
  NOWPAYMENTS_AUTH_PASSWORD: z.string(),

  NOWPAYMENTS_BASE_URL: z.string(),

  NOWPAYMENTS_IPN_SECRET: z.string(),

  NOWPAYMENTS_IPN_URL: z.string(),
});

export const MERGED_ENV_SCHEMA = z.object({
  ...NODE_ENV_SCHEMA.shape,
  ...CORE_ENV_SCHEMA.shape,
  ...SWAGGER_ENV_SCHEMA.shape,
  ...MAIL_ENV_SCHEMA.shape,
  ...AWS_ENV_SCHEMA.shape,
  ...AWS_COGNITO_ENV_SCHEMA.shape,
  ...AWS_S3_ENV_SCHEMA.shape,
  ...MAILERSEND_ENV_SCHEMA.shape,
  ...DB_ENV_SCHEMA.shape,
  ...JWT_ENV_SCHEMA.shape,
  ...INTERNAL_SECRET_ENV_SCHEMA.shape,
  ...STRIPE_ENV_SCHEMA.shape,
  ...FEE_ENV_SCHEMA.shape,
  ...RABBITMQ_ENV_SCHEMA.shape,
  ...PHONE_NOTIFICATION_ENV_SCHEMA.shape,
  ...ENTRUPY_ENV_SCHEMA.shape,
  ...PAYPAL_ENV_SCHEMA.shape,
  ...CRYPTO_PAY_ENV_SCHEMA.shape,
  ...NOWPAYMENTS_ENV_SCHEMA.shape,
});

export const env = MERGED_ENV_SCHEMA.parse(process.env);

export function isDevelopment() {
  return env.NODE_ENV === 'development';
}

export const EMAIL_AUTH_ENABLED = ['development', 'staging'].includes(
  process.env.NODE_ENV!,
);

