  @IsString()
  @IsOptional()
  patronymic?: string;

  @ApiProperty()
  @IsUUID()
  phoneOtpId: string;

  @ApiProperty()
  @IsUUID()
  emailOtpId: string;

  @ApiProperty()
  @IsEnum([UserRole.Bidder, UserRole.Seller, UserRole.Retailer])
  role: UserRole;
}

export class SendOtpDto {
  @ApiProperty()
  @IsOptional()
  @IsEmail()
  email?: string;

  @ApiProperty()
  @IsPhoneNumber()
  @IsOptional()
  phone?: string;

  @ApiProperty()
  @IsEnum(OtpType)
  type: OtpType;

  // Not required when type === SIGN_UP and both email + phone are provided
  // (both channels are handled in a single request).
  @ApiProperty({ required: false })
  @ValidateIf((o: SendOtpDto) => !(o.type === OtpType.SignUp && !!o.email && !!o.phone))
  @IsEnum(MediaType)
  mediaType?: MediaType;
}

export class ForgotPasswordDto {
  @ApiProperty({ required: false })
  @ValidateIf((o) => o.mediaType === MediaType.Email)
  @IsEmail()
  @IsNotEmpty()
  email?: string;

  @ApiProperty({ required: false })
  @ValidateIf((o) => o.mediaType === MediaType.Phone)
  @IsPhoneNumber()
  @IsNotEmpty()
  phone?: string;

  @ApiProperty({ enum: MediaType })
  @IsEnum(MediaType)
  mediaType: MediaType;
}

export class ConfirmForgotPasswordDto {
  @ApiProperty()
  @IsUUID()
  otpId: string;

  @ApiProperty()
  @IsString()
  @IsNotEmpty()
  newPassword: string;
}

export class VerifyOtpDto extends SendOtpDto {
  @ApiProperty()
  @IsString()
  @IsNotEmpty()
  otp: string;
}

export class PhoneExistsRequestDto {
  @ApiProperty()
  @IsPhoneNumber()
  phone: string;
}

export class EmailExistsRequestDto {
  @ApiProperty()
  @IsEmail()
  email: string;
}

