import { SetMetadata, UseGuards, applyDecorators } from '@nestjs/common';
import { ApiBearerAuth } from '@nestjs/swagger';

import { Permission, UserRole } from '@/db';

import { AuthGuard } from '../guards';

export function Protected(roles?: UserRole[], permission?: Permission) {
  const guards: any[] = [AuthGuard];

  const decorators = [UseGuards(...guards), ApiBearerAuth()];

  if (roles) {
    decorators.push(SetMetadata('roles', roles));
  }

  if (permission) {
    decorators.push(SetMetadata('permission', permission));
  }

  return applyDecorators(...decorators);
}

