import { z } from 'zod';

const zBoolean = () =>
  z
    .union([z.literal('true'), z.literal('false'), z.undefined()])
    .transform((value) => {
      if (value === undefined) {
        return value;
      }

      if (value === 'true') {
        return true;
      }

      return false;
    });

const zStrArray = () =>
  z.union([
    z.undefined().transform(() => [] as string[]),
    z
      .string()
      .transform((origins) =>
        origins.split(',').map((origin) => origin.trim()),
      ),
  ]);

