import { Module } from '@nestjs/common';
import { RouterModule, Routes } from '@nestjs/core';

import { AdminApiModule, adminApiRoutes } from './admin';
import { AppApiModule, appApiRoutes } from './app';
import { AuthApiModule, authApiRoutes } from './auth';
import { InternalApiModule, internalApiRoutes } from './internal';
import { PublicApiModule, publicApiRoutes } from './public';
import { RootController } from './root.controller';
import { NotificationModule } from '@/modules/notification';

const ROUTES: Routes = [
  adminApiRoutes,
  appApiRoutes,
  authApiRoutes,
  internalApiRoutes,
  publicApiRoutes,
];

@Module({
  imports: [
    AdminApiModule,
    AppApiModule,
    AuthApiModule,
    InternalApiModule,
    PublicApiModule,
    RouterModule.register(ROUTES),
    NotificationModule,
  ],
  controllers: [RootController],
})
export class ApiModule {}

