import { Readable } from 'node:stream';

import { MultipartFile } from '@fastify/multipart';
import { BadRequestException, Injectable } from '@nestjs/common';
import { TransactionHost } from '@nestjs-cls/transactional';
import { v4 as uuid } from 'uuid';

import { MimeType } from '@/common';
import { TransactionalAdapterTypeOrm } from '@/modules/global';
import { FileEntity, FileStatus } from '@/db';
import { StorageService } from './storage.service';

export enum S3Folder {
  FILES = 'files',
  STATIC = 'static',
  WITHDRAWAL_CONFIRMATIONS = 'withdrawal-confirmations',
  GUEST_UPLOADS = 'guest-uploads',
}

@Injectable()
export class FileService {
  constructor(
    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
    private readonly storageService: StorageService,
  ) {}

  async create(params: {
    mime: MimeType;
    fileName?: string;
    folder: S3Folder;
  }) {
    const { mime, fileName, folder } = params;

    const fileId = uuid();

    const path = `/${folder}/${fileId}`;

    const fileRepository = this.txHost.tx.getRepository(FileEntity);

    return fileRepository.save({
      id: fileId,
      path,
      mime,
      uploadedAt: new Date(),
      status: FileStatus.PENDING,
      name: fileName,
    });
  }

  async createPresignedPost(params: {
    mime: MimeType;
    fileName?: string;
    folder: S3Folder;
  }) {
    const file = await this.create(params);

    const presigned = await this.storageService.signPostUrl(
      file.path,
      file.mime,
    );

    return { presigned, file };
  }

  async markUploaded(params: { fileId: string }) {
    const { fileId } = params;

    await this.txHost.withTransaction(async () => {
      const fileRepository = this.txHost.tx.getRepository(FileEntity);

      const file = await fileRepository.findOne({
        where: {
          id: fileId,
        },
      });

      if (!file) {
        throw new BadRequestException('File not found');
      }

      await fileRepository.update(
        { id: fileId },
        { status: FileStatus.UPLOADED },
      );
    });
  }

  async uploadOne(params: {
    folder: S3Folder;
    file: MultipartFile;
    fileName?: string;
  }) {
    const { folder, file, fileName } = params;

    const fileId = uuid();
    const path = `/${folder}/${fileId}`;

    return this.txHost.withTransaction(async () => {
      const fileRepository = this.txHost.tx.getRepository(FileEntity);

      const fileEntity = await fileRepository.save({
        id: fileId,
        path,
        mime: file.mimetype,
        name: fileName || file.filename,
        status: FileStatus.UPLOADED,
        uploadedAt: new Date(),
      });
      await this.storageService.upload(path, await file.toBuffer());

      return fileEntity;
    });
  }

  uploadOneWithStream(params: {
    folder: S3Folder;
    file: Readable;
    fileName: string;
    mime: MimeType;
  }) {
    const { folder, file, fileName, mime } = params;

    const fileId = uuid();

    const path = `/${folder}/${fileId}`;

    return this.txHost.withTransaction(async () => {
      const fileRepository = this.txHost.tx.getRepository(FileEntity);
      const fileEntity = await fileRepository.save({
        id: fileId,
        path,
        mime,
        name: fileName,
        status: FileStatus.UPLOADED,
        uploadedAt: new Date(),
      });
      await this.storageService.upload(path, file);

      return fileEntity;
    });
  }

  async getOne(fileId: string): Promise<FileEntity | null> {
    const fileRepository = this.txHost.tx.getRepository(FileEntity);

    return fileRepository.findOne({
      where: { id: fileId },
    });
  }

  async getSignedUrl(params: { fileId: string }) {
    const { fileId } = params;

    const fileRepository = this.txHost.tx.getRepository(FileEntity);

    const file = await fileRepository.findOne({
      where: { id: fileId },
    });

    if (!file) {
      throw new BadRequestException();
    }

    return this.storageService.signGetUrl(file);
  }

  async deleteOrphanedFiles(): Promise<{ deletedCount: number }> {
    const fileRepository = this.txHost.tx.getRepository(FileEntity);

    const cutoff = new Date(Date.now() - 24 * 60 * 60 * 1000);

    const orphans = await fileRepository
      .createQueryBuilder('file')
      .where('file.assetPhotoId IS NULL')
      .andWhere('file.assetAuthPhotoId IS NULL')
      .andWhere('"file"."ticket_id" IS NULL')
      .andWhere(
        'NOT EXISTS (SELECT 1 FROM "user" u WHERE u.photo_file_id = file.id)',
      )
      .andWhere('file.createdAt < :cutoff', { cutoff })
      .getMany();

    if (orphans.length === 0) {
      return { deletedCount: 0 };
    }

    await Promise.all(
      orphans.map((file) => this.storageService.delete(file.path)),
    );

    await fileRepository.delete(orphans.map((f) => f.id));

    return { deletedCount: orphans.length };
  }

  async deleteOne(params: { fileId: string }) {
    const { fileId } = params;

    const fileRepository = this.txHost.tx.getRepository(FileEntity);

    const file = await fileRepository.findOne({
      where: { id: fileId },
    });

    if (!file) {
      throw new BadRequestException();
    }

    return this.txHost.withTransaction(async () => {
      const fileRepository = this.txHost.tx.getRepository(FileEntity);

      await this.storageService.delete(file.path);
      await fileRepository.delete({ id: file.id });

      return file;
    });
  }
}

