import { Column, Entity, Index, JoinColumn, ManyToOne } from 'typeorm';

import { BaseEntity } from '../utils';
import { AssetEntity } from './asset.entity';
import { TicketEntity } from '@/db';

export enum FileStatus {
  PENDING = 'PENDING',
  UPLOADED = 'UPLOADED',
}

@Entity('file', {
  comment: 'File stored in S3',
})
export class FileEntity extends BaseEntity {
  @Column({
    type: 'enum',
    enum: FileStatus,
    default: FileStatus.UPLOADED,
    comment: 'Whether the file is pending upload or already uploaded',
  })
  status: FileStatus;

  @Column({
    type: 'varchar',
    comment: 'Path in S3 "<folderName>/<fileId>", e.g. /files/1234567890',
  })
  path: string;

  @Column({
    type: 'varchar',
    comment: 'Original file name',
  })
  name: string;

  @Column({
    type: 'varchar',
    comment: 'MIME type of the file',
  })
  mime: string;

  @Column({
    name: 'uploaded_at',
    type: 'timestamp',
    default: () => 'CURRENT_TIMESTAMP',
  })
  uploadedAt: Date;

  // Relations

  @ManyToOne(() => AssetEntity, (entity) => entity.photos, {
    nullable: true,
  })
  @JoinColumn({ name: 'asset_photo_id', referencedColumnName: 'id' })
  assetPhoto: AssetEntity | null;

  @Index('idx_file_asset_photo')
  @Column({ type: 'uuid', name: 'asset_photo_id', nullable: true })
  assetPhotoId: string | null;

  @ManyToOne(() => AssetEntity, (entity) => entity.authPhotos, {
    nullable: true,
  })
  @JoinColumn({ name: 'asset_auth_photo_id', referencedColumnName: 'id' })
  assetAuthPhoto: AssetEntity | null;

  @Index('idx_file_asset_auth_photo')
  @Column({ type: 'uuid', name: 'asset_auth_photo_id', nullable: true })
  assetAuthPhotoId: string | null;

  @ManyToOne(() => TicketEntity, (entity) => entity.attachedFiles, {
    nullable: true,
  })
  @JoinColumn({ name: 'ticket_id', referencedColumnName: 'id' })
  ticket: TicketEntity | null;
}

