import { Readable } from 'node:stream';

import {
  DeleteObjectCommand,
  GetObjectCommand,
  GetObjectCommandInput,
  PutObjectCommand,
  S3Client,
} from '@aws-sdk/client-s3';
import {
  PresignedPostOptions,
  createPresignedPost,
} from '@aws-sdk/s3-presigned-post';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { Injectable } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { NodeJsRuntimeStreamingBlobPayloadInputTypes } from '@smithy/types';

import { MimeType } from '@/common';
import { FileEntity } from '@/db';

@Injectable()
export class StorageService {
  private readonly s3: S3Client;
  private readonly bucket: string;

  constructor(private readonly configService: ConfigService) {
    this.s3 = new S3Client({
      region: this.configService.get('AWS_S3_REGION'),
      credentials: {
        accessKeyId: this.configService.get('AWS_ACCESS_KEY_ID')!,
        secretAccessKey: this.configService.get('AWS_SECRET_ACCESS_KEY')!,
      },
    });
    this.bucket = this.configService.get('AWS_S3_BUCKET')!;
  }

  static getFileKey(path: string): string {
    return path[0] === '/' ? path.substring(1) : path;
  }

  async upload(
    path: string,
    blob: NodeJsRuntimeStreamingBlobPayloadInputTypes,
  ) {
    await this.s3.send(
      new PutObjectCommand({
        Bucket: this.bucket,
        Key: StorageService.getFileKey(path),
        Body: blob,
      }),
    );
  }

  async get(path: string) {
    const { Body } = await this.s3.send(
      new GetObjectCommand({
        Bucket: this.bucket,
        Key: StorageService.getFileKey(path),
      }),
    );

    return Body as Readable;
  }

  async getBuffer(path: string): Promise<Buffer> {
    const stream = await this.get(path);
    return this.streamToBuffer(stream);
  }

  private async streamToBuffer(stream: Readable): Promise<Buffer> {
    const chunks: Buffer[] = [];
    return new Promise((resolve, reject) => {
      stream.on('data', (chunk) => chunks.push(chunk));
      stream.on('error', reject);
      stream.on('end', () => resolve(Buffer.concat(chunks)));
    });
  }

  async signGetUrl(
    file: FileEntity,
    options?: Omit<GetObjectCommandInput, 'Key' | 'Bucket'>,
  ) {
    const fileName = file.name;

    return getSignedUrl(
      this.s3,
      new GetObjectCommand({
        ...options,
        Bucket: this.bucket,
        Key: StorageService.getFileKey(file.path),
        ResponseContentDisposition: `attachment; filename="${fileName}"`,
      }),
      { expiresIn: 60 * 15 },
    );
  }

  async signPostUrl(path: string, mime: MimeType) {
    const params: PresignedPostOptions = {
      Bucket: this.bucket,
      Key: StorageService.getFileKey(path),
      Conditions: [
        [
          'content-length-range',
          0,
          this.configService.get<number>('AWS_S3_UPLOAD_FILE_SIZE_LIMIT')!,
        ],
        ['eq', '$Content-Type', mime],
      ],
      Fields: {
        'Content-Type': mime,
      },
      Expires: 60 * 15,
    };

    return createPresignedPost(this.s3, params);
  }

  async delete(path: string) {
    await this.s3.send(
      new DeleteObjectCommand({
        Bucket: this.bucket,
        Key: StorageService.getFileKey(path),
      }),
    );
  }
}

