42	  public async canActivate(context: ExecutionContext): Promise<boolean> {
43	    const isUnProtectedDecoratorSpecified =
44	      this.reflector.getAllAndOverride<boolean>(UN_PROTECT_KEY, [
45	        context.getHandler(),
46	        context.getClass(),
47	      ]);
48	
49	    if (isUnProtectedDecoratorSpecified) {
50	      return true;
51	    }
52	
53	    const type = context.getType();
54	
55	    const requiredUserRoles = this.reflector.getAllAndOverride<UserRole[]>(
56	      'roles',
57	      [context.getHandler(), context.getClass()],
58	    );
59	
60	    const requiredPermission = this.reflector.getAllAndOverride<Permission>(
61	      'permission',
62	      [context.getHandler(), context.getClass()],
63	    );
64	
65	    if (type === 'http') {
66	      return this.handleHttp(context, requiredUserRoles, requiredPermission);
67	    }
68	
69	    return false;
70	  }
