  private async resolveEmailDev(jwt: string): Promise<string> {
    // 1. Our own JWT (social auth in dev)
    try {
      const payload = this.jwtService.verify<{ sub: string }>(jwt, {
        secret: env.JWT_SECRET,
      });
      if (payload?.sub) return payload.sub;
    } catch {
      // not our JWT
    }

    // 2. Cognito token (social auth via Cognito in dev)
    try {
      return await this.cognitoService.getAccessTokenOwnerEmail(jwt);
    } catch {
      // not a Cognito token
    }

    // 3. Raw email (standard dev login)
    return jwt;
  }
}

